body:
A `? :` conditional, where the expression is wide, can cause both sides to get evaluated always, rather than properly short-circuit, due to the emitted code having to compute arguments before calling into for the VL_COND_W* function that resolves the condition.  The below example fires a null pointer error incorrectly due to this. This is breaking uvm_tests tests/70regs/90Mantis/7082.

I have two potential fixes but both are moderately ugly.

@gezalore you have the pull that will convert some of these, would it work on this case?

<details>
<summary>Test</summary>

```
// verilog_format: off
`define stop $stop
`define checkh(gotv,expv) do if ((gotv) !== (expv)) begin $write("%%Error: %s:%0d:  got=%0x exp=%0x (%s !== %s)\n", `__FILE__,`__LINE__, (gotv), (expv), `"gotv`", `"expv`"); `stop; end while(0);
`ifdef verilator
 `define optimize_barrier $c("")
`else
 `define optimize_barrier
`endif
// verilog_format: on

module t;

  class Map;
    virtual function bit [95:0] get_value();
      bit [95:0] result = 96'h11111111_22222222_33333333;
      `optimize_barrier;
      return result;
    endfunction
  endclass

  class Cls;
    function bit [95:0] get_default();
      bit [95:0] result = 96'haaaaaaaa_bbbbbbbb_cccccccc;
      `optimize_barrier;
      return result;
    endfunction

    function bit [95:0] compute_LL(Map map);
      bit [95:0] result;
      `optimize_barrier;
      // Wide operation is required, as results in VL_COND call which evaluates
      // arguments
      result = map == null ? this.get_default() : map.get_value();
      `optimize_barrier;
      return result;
    endfunction
 endclass

  initial begin
    Cls c;
    Map mnull;
    Map m;
    bit [95:0] res;

    c = new;
    m = new;

    res = c.compute_LL(mnull);
    `checkh(res, 96'haaaaaaaa_bbbbbbbb_cccccccc);
    res = c.compute_LL(m);
    `checkh(res, 96'h11111111_22222222_33333333);

    $finish;
  end

endmodule
```
</details>

